async def generate_sse_stream(model: str, user_input: str, model_info: dict, api_key: str, api_base: str):
    """生成 SSE 流式响应（兼容 Codex Responses API）"""
    try:
        # 构建流式 Chat Completions 请求
        chat_payload = {
            "model": model_info.get("model_id", model) if model_info else model,
            "messages": [
                {
                    "role": "user",
                    "content": [
                        {"type": "text", "text": user_input}
                    ]
                }
            ],
            "temperature": 0.7,
            "max_tokens": 2048,
            "stream": True
        }

        response_id = f"resp_{int(time.time())}"

        async with httpx.AsyncClient(timeout=120.0) as client:
            async with client.stream(
                "POST",
                api_base,
                json=chat_payload,
                headers={
                    "Authorization": f"Bearer {api_key}",
                    "Content-Type": "application/json"
                }
            ) as resp:
                if resp.status_code != 200:
                    error_text = await resp.aread()
                    raise Exception(f"Upstream error: {error_text.decode()}")

                # 发送 response.created 事件
                yield f"data: {json.dumps({'type': 'response.created', 'response': {'id': response_id, 'status': 'in_progress'}})}\n\n"

                full_content = ""

                # 处理 SSE 流
                async for line in resp.aiter_lines():
                    if line.startswith("data: "):
                        data = line[6:]
                        if data.strip() == "[DONE]":
                            break

                        try:
                            chunk = json.loads(data)
                            delta = chunk.get("choices", [{}])[0].get("delta", {})
                            content = delta.get("content", "")

                            if content:
                                full_content += content
                                # 发送 response.output_text.delta 事件
                                yield f"data: {json.dumps({'type': 'response.output_text.delta', 'delta': content, 'response_id': response_id})}\n\n"
                        except json.JSONDecodeError:
                            continue

                # 发送 response.completed 事件
                yield f"data: {json.dumps({'type': 'response.completed', 'response': {'id': response_id, 'status': 'completed', 'output': full_content, 'model': model}})}\n\n"

    except Exception as e:
        yield f"data: {json.dumps({'type': 'error', 'error': str(e)})}\n\n"

@app.post("/responses")
@app.post("/v1/responses")
async def responses_proxy(
    payload: Dict[str, Any],
    authorization: Optional[str] = Header(None)
):
    """
    OpenAI Responses API 端点
    转换为 Chat Completions API 调用阿里云
    支持 /responses 和 /v1/responses 两个路径
    支持流式和非流式响应
    """
    try:
        # 1. 解析 Responses API 请求
        model = payload.get("model", "qwen3.5-plus")
        stream = payload.get("stream", True)  # Codex 默认使用流式
        user_input = payload.get("input")

        # 处理 Codex 的 input 格式（可能是字符串或数组）
        if isinstance(user_input, list):
            user_input = " ".join([item.get("text", str(item)) if isinstance(item, dict) else str(item) for item in user_input])

        if not user_input:
            raise HTTPException(status_code=400, detail="Missing 'input' field")

        # 2. 获取模型配置
        model_info = get_model_info(model)
        api_base = model_info.get("api_base") if model_info else None
        api_key = get_api_key(model)

        if not api_base:
            raise HTTPException(status_code=400, detail=f"Model not configured: {model}")

        # 3. 流式响应
        if stream:
            return StreamingResponse(
                generate_sse_stream(model, user_input, model_info, api_key, api_base),
                media_type="text/event-stream",
                headers={
                    "Cache-Control": "no-cache",
                    "Connection": "keep-alive",
                    "X-Accel-Buffering": "no"
                }
            )

        # 4. 非流式响应（备用）
        chat_payload = {
            "model": model_info.get("model_id", model) if model_info else model,
            "messages": [
                {
                    "role": "user",
                    "content": [
                        {"type": "text", "text": user_input}
                    ]
                }
            ],
            "temperature": 0.7,
            "max_tokens": 2048,
            "stream": False
        }

        async with httpx.AsyncClient(timeout=60.0) as client:
            resp = await client.post(
                api_base,
                json=chat_payload,
                headers={
                    "Authorization": f"Bearer {api_key}",
                    "Content-Type": "application/json"
                }
            )

            if resp.status_code != 200:
                raise HTTPException(
                    status_code=resp.status_code,
                    detail=f"Upstream error: {resp.text}"
                )

            chat_resp = resp.json()

        choice = chat_resp.get("choices", [{}])[0]
        message = choice.get("message", {})
        output = message.get("content", "")

        return {
            "id": f"resp_{chat_resp.get('id', 'unknown')}",
            "object": "response",
            "created_at": chat_resp.get('created', 1709625600),
            "status": "completed",
            "model": model,
            "output": output,
            "usage": chat_resp.get("usage", {})
        }

    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

