## 1. 原地快速排序（修改原数组）

```typescript
/**
 * 快速排序 - 原地排序版本
 * @param arr - 要排序的数组（会被修改）
 * @param left - 左边界索引（默认 0）
 * @param right - 右边界索引（默认 arr.length - 1）
 * @returns 排序后的数组（与原数组引用相同）
 */
function quickSortInPlace<T>(
  arr: T[],
  left: number = 0,
  right: number = arr.length - 1
): T[] {
  if (left < right) {
    const pivotIndex = partition(arr, left, right);
    quickSortInPlace(arr, left, pivotIndex - 1);
    quickSortInPlace(arr, pivotIndex + 1, right);
  }
  return arr;
}

/**
 * 分区函数 - 将数组分为小于和大于基准值的两部分
 */
function partition<T>(arr: T[], left: number, right: number): number {
  const pivot = arr[right]; // 选择最后一个元素作为基准
  let i = left - 1;

  for (let j = left; j < right; j++) {
    if (arr[j] <= pivot) {
      i++;
      [arr[i], arr[j]] = [arr[j], arr[i]]; // 交换元素
    }
  }

  [arr[i + 1], arr[right]] = [arr[right], arr[i + 1]]; // 将基准放到中间位置
  return i + 1;
}
```

## 2. 返回新数组的快速排序（不修改原数组）

```typescript
/**
 * 快速排序 - 返回新数组版本
 * @param arr - 要排序的数组
 * @returns 排序后的新数组
 */
function quickSort<T>(arr: T[]): T[] {
  if (arr.length <= 1) return arr;

  const pivot = arr[Math.floor(arr.length / 2)];
  const left = arr.filter(x => x < pivot);
  const middle = arr.filter(x => x === pivot);
  const right = arr.filter(x => x > pivot);

  return [...quickSort(left), ...middle, ...quickSort(right)];
}
```

## 3. 支持自定义比较函数的版本

```typescript
/**
 * 快速排序 - 支持自定义比较函数
 * @param arr - 要排序的数组
 * @param compare - 比较函数，返回负数表示 a < b，0 表示相等，正数表示 a > b
 * @returns 排序后的新数组
 */
function quickSortWithComparator<T>(
  arr: T[],
  compare: (a: T, b: T) => number
): T[] {
  if (arr.length <= 1) return arr;

  const pivot = arr[Math.floor(arr.length / 2)];
  const left = arr.filter(x => compare(x, pivot) < 0);
  const middle = arr.filter(x => compare(x, pivot) === 0);
  const right = arr.filter(x => compare(x, pivot) > 0);

  return [
    ...quickSortWithComparator(left, compare),
    ...middle,
    ...quickSortWithComparator(right, compare)
  ];
}
```

## 4. 使用示例

```typescript
// 示例 1：原地排序数字数组
const numbers = [3, 6, 1, 5, 2, 4];
quickSortInPlace(numbers);
console.log(numbers); // [1, 2, 3, 4, 5, 6]

// 示例 2：返回新数组
const original = [5, 2, 9, 1, 7];
const sorted = quickSort(original);
console.log(sorted);    // [1, 2, 5, 7, 9]
console.log(original);  // [5, 2, 9, 1, 7]（未改变）

// 示例 3：排序对象数组（按年龄）
interface Person {
  name: string;
  age: number;
}

const people: Person[] = [
  { name: 'Alice', age: 25 },
  { name: 'Bob', age: 20 },
  { name: 'Charlie', age: 30 }
];

const sortedPeople = quickSortWithComparator(people, (a, b) => a.age - b.age);
console.log(sortedPeople);
// [{ name: 'Bob', age: 20 }, { name: 'Alice', age: 25 }, { name: 'Charlie', age: 30 }]

// 示例 4：降序排序
const descSorted = quickSortWithComparator(numbers, (a, b) => b - a);
console.log(descSorted); // [6, 5, 4, 3, 2, 1]
```

## 5. 算法特性

| 特性         | 说明                           |
|--------------|--------------------------------|
| 时间复杂度   | 平均 O(n log n)，最坏 O(n²)     |
| 空间复杂度   | 原地版 O(log n)，新版 O(n)      |
| 稳定性       | 不稳定排序                     |
| 适用场景     | 通用排序，适合大数据量         |

## 6. 使用建议

- ✅ 小数组或需保留原数组：使用 `quickSort`
- ✅ 大数组且允许修改原数组：使用 `quickSortInPlace`
- ✅ 自定义排序逻辑（如对象、降序）：使用 `quickSortWithComparator`

